question:
某银行核心系统需实现批量转账批次处理模块，具体约束与要求如下：
1. 单批次最多处理1000笔转账交易，单笔转账金额必须为1~50000元的正整数，超出范围的交易直接导致整个批次回滚；
2. 手续费规则：转账金额≤1000元时固定收取1元手续费；1000元<转账金额≤10000元时，手续费为转账金额的0.1%向上取整；转账金额>10000元时，手续费为转账金额的0.05%向上取整；转出账户需承担手续费，即转出账户余额需≥转账金额+对应手续费才能执行转账；
3. 批次处理分三步执行：① 校验所有交易的转出、转入账户是否存在且未冻结，若存在任意一笔校验不通过则整个批次回滚，返回「账户异常」；② 校验所有交易的金额合规性、转出账户余额充足性，若存在任意一笔校验不通过则整个批次回滚，返回「余额不足/金额异常」；③ 顺序执行每笔转账的扣款、入账操作，若执行过程中任意一笔操作失败，则回滚所有已成功执行的前序交易，返回「执行失败」；
4. 批次处理成功时，需返回成功处理的交易笔数、总转账金额、总手续费金额，所有操作需保证原子性，避免出现部分成功部分失败的资金不一致问题。

现给出该模块的参考伪代码实现，请你完成以下任务：
1. 逐步推理定位代码中所有逻辑错误、边界条件处理疏漏、异常处理缺陷，需至少完成5步独立推理；
2. 说明每个错误/疏漏在特定场景下的具体影响；
3. 给出修正后的完整正确实现（可保留伪代码格式，需覆盖所有约束要求）。

参考伪代码：
function batchTransfer(transactions) {
  if (transactions.length === 0 || transactions.length > 1000) {
    return {code: 400, msg: "交易笔数不符合要求"};
  }
  // 第一步：校验账户状态
  for (let i = 0; i < transactions.length; i++) {
    const tx = transactions[i];
    if (!accountExists(tx.fromAccount) || isAccountFrozen(tx.fromAccount)) {
      rollbackAll(); // 回滚所有已执行操作
      return {code: 401, msg: "账户异常"};
    }
  }
  // 第二步：校验金额和余额
  for (let i = 0; i < transactions.length; i++) {
    const tx = transactions[i];
    if (tx.amount < 1 || tx.amount > 50000) {
      rollbackAll();
      return {code: 402, msg: "金额不符合要求"};
    }
    const fee = calculateFee(tx.amount);
    if (getBalance(tx.fromAccount) < tx.amount + fee) {
      rollbackAll();
      return {code: 403, msg: "余额不足"};
    }
  }
  // 第三步：执行转账
  let successCount = 0;
  let totalAmount = 0;
  let totalFee = 0;
  for (let i = 0; i < transactions.length; i++) {
    const tx = transactions[i];
    const fee = calculateFee(tx.amount);
    try {
      deductAmount(tx.fromAccount, tx.amount + fee);
      addAmount(tx.toAccount, tx.amount);
      successCount++;
      totalAmount += tx.amount;
      totalFee += fee;
    } catch (e) {
      rollbackAll(); // 回滚所有已执行操作
      return {code: 404, msg: "执行失败"};
    }
  }
  return {code: 200, data: {successCount, totalAmount, totalFee}};
}
function calculateFee(amount) {
  if (amount <= 1000) return 1;
  if (amount <= 10000) return Math.ceil(amount * 0.001);
  return Math.ceil(amount * 0.005);
}
